package com.soumyajit.gradlemc.foundation;
import java.util.*;
public final class TaskRegistry { private final NavigableMap<TaskId,TaskCore.Definition> tasks=new TreeMap<>(); public synchronized void register(TaskCore.Definition task){if(tasks.size()>=128)throw new IllegalStateException("Task registry limit reached");if(tasks.putIfAbsent(task.id(),task)!=null)throw new IllegalArgumentException("Duplicate task ID: "+task.id());} public synchronized Optional<TaskCore.Definition> get(TaskId id){return Optional.ofNullable(tasks.get(id));} public synchronized List<TaskCore.Definition> all(){return List.copyOf(tasks.values());} public synchronized TaskCore.Plan plan(List<TaskId> roots,TaskCore.Context context,boolean force){if(roots==null||roots.isEmpty())throw new IllegalArgumentException("At least one root task is required");List<TaskId> order=new ArrayList<>();Set<TaskId> done=new HashSet<>();Deque<TaskId> visiting=new ArrayDeque<>();for(TaskId root:new TreeSet<>(roots))visit(root,visiting,done,order);List<TaskCore.PlanNode> nodes=new ArrayList<>();for(TaskId id:order){TaskCore.Definition t=tasks.get(id);TaskCore.Availability a=t.availability().apply(context);List<TaskCore.Reason> reasons=new ArrayList<>();boolean direct=roots.contains(id);reasons.add(direct?TaskCore.Reason.REQUESTED_DIRECTLY:TaskCore.Reason.REQUIRED_DEPENDENCY);if(force)reasons.add(TaskCore.Reason.FORCED_REFRESH);else reasons.add(TaskCore.Reason.NO_PREVIOUS_RESULT);if(!a.available())reasons.add(TaskCore.Reason.UNAVAILABLE);String why=!a.available()?"Unavailable because "+a.reason():direct?"Requested directly.":"Required dependency.";nodes.add(new TaskCore.PlanNode(id,t.dependencies(),a.available(),reasons,a,why));}return new TaskCore.Plan(roots,nodes,List.of());} private void visit(TaskId id,Deque<TaskId> visiting,Set<TaskId> done,List<TaskId> order){if(done.contains(id))return;if(!tasks.containsKey(id))throw new IllegalArgumentException("Missing task dependency: "+id);if(visiting.contains(id)){List<String> cycle=new ArrayList<>();boolean add=false;for(TaskId n:visiting){if(n.equals(id))add=true;if(add)cycle.add(n.toString());}cycle.add(id.toString());throw new IllegalArgumentException("Task dependency cycle: "+String.join(" -> ",cycle));}visiting.addLast(id);for(TaskId d:tasks.get(id).dependencies())visit(d,visiting,done,order);visiting.removeLast();done.add(id);order.add(id);} }
